class SampleObserverComponent final : public nsIObserverService {
 public:
  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVERSERVICE

  SampleObserverComponent();

  /**
   * Custom initialization method for the observer component.
   */
  nsresult Initialize();

  /**
   * Shutdown the component.
   */
  void Shutdown();

 private:
  ~SampleObserverComponent();

  // Reference to the actual observer service implementation
  nsCOMPtr<nsIObserverService> mObserverService;
  bool mIsShuttingDown;
};

#endif /* SampleObserverComponent_h_ */

