#include "SampleObserverComponent.h"
#include "nsServiceManagerUtils.h"
#include "nsString.h"
#include "mozilla/Services.h"

// Implementation of nsISupports for reference counting
NS_IMPL_ISUPPORTS(SampleObserverComponent, nsIObserverService)

// Factory constructor macro - generates the constructor function
// This is used by the component registration system to instantiate the component
NS_GENERIC_FACTORY_CONSTRUCTOR_INIT(SampleObserverComponent, Initialize)

// ============================================================================
// SampleObserverComponent Implementation
// ============================================================================

SampleObserverComponent::SampleObserverComponent()
    : mIsShuttingDown(false) {}

SampleObserverComponent::~SampleObserverComponent() {
  Shutdown();
}

nsresult SampleObserverComponent::Initialize() {
  // Get the global observer service
  mObserverService = mozilla::services::GetObserverService();
  if (!mObserverService) {
    return NS_ERROR_FAILURE;
  }

  return NS_OK;
}

void SampleObserverComponent::Shutdown() {
  if (mIsShuttingDown) {
    return;
  }

  mIsShuttingDown = true;
  mObserverService = nullptr;
}

// ============================================================================
// nsIObserverService Implementation
// ============================================================================

NS_IMETHODIMP
SampleObserverComponent::AddObserver(nsIObserver* aObserver,
                                     const char* aTopic,
                                     bool aOwnsWeak) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->AddObserver(aObserver, aTopic, aOwnsWeak);
}

NS_IMETHODIMP
SampleObserverComponent::RemoveObserver(nsIObserver* aObserver,
                                        const char* aTopic) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->RemoveObserver(aObserver, aTopic);
}

NS_IMETHODIMP
SampleObserverComponent::NotifyObservers(nsISupports* aSubject,
                                         const char* aTopic,
                                         const char16_t* aData) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->NotifyObservers(aSubject, aTopic, aData);
}

NS_IMETHODIMP
SampleObserverComponent::HasObservers(const char* aTopic, bool* _retval) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->HasObservers(aTopic, _retval);
}

NS_IMETHODIMP
SampleObserverComponent::EnumerateObservers(const char* aTopic,
                                            nsISimpleEnumerator** _retval) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->EnumerateObservers(aTopic, _retval);
}

nsresult SampleObserverComponent::NotifyWhenScriptSafe(
    nsISupports* aSubject,
    const char* aTopic,
    const char16_t* aData) {
  if (!mObserverService) {
    return NS_ERROR_NOT_INITIALIZED;
  }

  return mObserverService->NotifyWhenScriptSafe(aSubject, aTopic, aData);
}

